88: // readPluginManifest attempts to read and verify the plugin manifest
89: // if any error occurs or the manifest is not valid, this will return an error
90: func (s *Signature) readPluginManifest(ctx context.Context, body []byte) (*PluginManifest, error) {
91: 	block, _ := clearsign.Decode(body)
92: 	if block == nil {
93: 		return nil, errors.New("unable to decode manifest")
94: 	}
95: 
96: 	// Convert to a well typed object
97: 	var manifest PluginManifest
98: 	err := json.Unmarshal(block.Plaintext, &manifest)
99: 	if err != nil {
100: 		return nil, fmt.Errorf("%v: %w", "Error parsing manifest JSON", err)
101: 	}
102: 
103: 	if err = s.validateManifest(ctx, manifest, block); err != nil {
104: 		return nil, err
105: 	}
106: 
107: 	return &manifest, nil
108: }
109: 
110: var ErrSignatureTypeUnsigned = errors.New("plugin is unsigned")
111: 
112: // ReadPluginManifestFromFS reads the plugin manifest from the provided plugins.FS.
113: // If the manifest is not found, it will return an error wrapping ErrSignatureTypeUnsigned.
114: func (s *Signature) ReadPluginManifestFromFS(ctx context.Context, pfs plugins.FS) (*PluginManifest, error) {
115: 	f, err := pfs.Open("MANIFEST.txt")
116: 	if err != nil {
117: 		if errors.Is(err, plugins.ErrFileNotExist) {
118: 			return nil, fmt.Errorf("%w: could not find a MANIFEST.txt", ErrSignatureTypeUnsigned)
119: 		}
120: 		return nil, fmt.Errorf("could not open MANIFEST.txt: %w", err)
121: 	}
122: 	defer func() {
123: 		if f == nil {
124: 			return
125: 		}
126: 		if err = f.Close(); err != nil {
127: 			s.log.Warn("Failed to close plugin MANIFEST file", "error", err)
128: 		}
129: 	}()
130: 
131: 	byteValue, err := io.ReadAll(f)
132: 	if err != nil || len(byteValue) < 10 {
133: 		return nil, fmt.Errorf("%w: MANIFEST.txt is invalid", ErrSignatureTypeUnsigned)
134: 	}
135: 
136: 	manifest, err := s.readPluginManifest(ctx, byteValue)
137: 	if err != nil {
138: 		return nil, err
139: 	}
140: 	return manifest, nil
141: }
