17: // DefaultConstructor implements the default ConstructFunc used for the Construct step of the Bootstrap stage.
18: //
19: // It uses a pluginFactoryFunc to create plugins and the signatureCalculator to calculate the plugin's signature state.
20: type DefaultConstructor struct {
21: 	pluginFactoryFunc   pluginFactoryFunc
22: 	signatureCalculator plugins.SignatureCalculator
23: 	log                 log.Logger
24: }
25: 
26: // DefaultConstructFunc is the default ConstructFunc used for the Construct step of the Bootstrap stage.
27: func DefaultConstructFunc(cfg *config.PluginManagementCfg, signatureCalculator plugins.SignatureCalculator, assetProvider pluginassets.Provider) ConstructFunc {
28: 	return NewDefaultConstructor(cfg, signatureCalculator, assetProvider).Construct
29: }
30: 
31: // DefaultDecorateFuncs are the default DecorateFuncs used for the Decorate step of the Bootstrap stage.
32: func DefaultDecorateFuncs(cfg *config.PluginManagementCfg, cdn *pluginscdn.Service) []DecorateFunc {
33: 	return []DecorateFunc{
34: 		AppDefaultNavURLDecorateFunc,
35: 		TemplateDecorateFunc,
36: 		AppChildDecorateFunc(),
37: 		SkipHostEnvVarsDecorateFunc(cfg),
38: 		LoadingStrategyDecorateFunc(cfg, cdn),
39: 	}
40: }
41: 
42: // NewDefaultConstructor returns a new DefaultConstructor.
43: func NewDefaultConstructor(cfg *config.PluginManagementCfg, signatureCalculator plugins.SignatureCalculator, assetProvider pluginassets.Provider) *DefaultConstructor {
44: 	return &DefaultConstructor{
45: 		pluginFactoryFunc:   NewDefaultPluginFactory(&cfg.Features, assetProvider).createPlugin,
46: 		signatureCalculator: signatureCalculator,
47: 		log:                 log.New("plugins.construct"),
48: 	}
49: }
50: 
51: // Construct will calculate the plugin's signature state and create the plugin using the pluginFactoryFunc.
52: func (c *DefaultConstructor) Construct(ctx context.Context, src plugins.PluginSource, bundle *plugins.FoundBundle) ([]*plugins.Plugin, error) {
53: 	sig, err := c.signatureCalculator.Calculate(ctx, src, bundle.Primary)
54: 	if err != nil {
55: 		c.log.Warn("Could not calculate plugin signature state", "pluginId", bundle.Primary.JSONData.ID, "error", err)
56: 		return nil, err
57: 	}
58: 	plugin, err := c.pluginFactoryFunc(bundle, src.PluginClass(ctx), sig)
59: 	if err != nil {
60: 		c.log.Error("Could not create primary plugin base", "pluginId", bundle.Primary.JSONData.ID, "error", err)
61: 		return nil, err
62: 	}
63: 	res := make([]*plugins.Plugin, 0, len(plugin.Children)+1)
64: 	res = append(res, plugin)
65: 	res = append(res, plugin.Children...)
66: 	return res, nil
67: }
