69: // AppDefaultNavURLDecorateFunc is a DecorateFunc that sets the default nav URL for app plugins.
70: func AppDefaultNavURLDecorateFunc(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
71: 	if p.IsApp() {
72: 		setDefaultNavURL(p)
73: 	}
74: 	return p, nil
75: }
76: 
77: // TemplateDecorateFunc is a DecorateFunc that removes the placeholder for the version and last_update fields.
78: func TemplateDecorateFunc(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
79: 	// %VERSION% and %TODAY% are valid values, according to the plugin schema
80: 	// but it's meant to be replaced by the build system with the actual version and date.
81: 	// If not, it's the same than not having a version or a date.
82: 	if p.Info.Version == "%VERSION%" {
83: 		p.Info.Version = ""
84: 	}
85: 
86: 	if p.Info.Updated == "%TODAY%" {
87: 		p.Info.Updated = ""
88: 	}
89: 
90: 	return p, nil
91: }
92: 
93: func setDefaultNavURL(p *plugins.Plugin) {
94: 	// slugify pages
95: 	for _, include := range p.Includes {
96: 		if include.Slug == "" {
97: 			include.Slug = slugify.Slugify(include.Name)
98: 		}
99: 
100: 		if !include.DefaultNav {
101: 			continue
102: 		}
103: 
104: 		if include.Type == "page" {
105: 			p.DefaultNavURL = path.Join("/plugins/", p.ID, "/page/", include.Slug)
106: 		}
107: 		if include.Type == "dashboard" {
108: 			dboardURL := include.DashboardURLPath()
109: 			if dboardURL == "" {
110: 				p.Logger().Warn("Included dashboard is missing a UID field")
111: 				continue
112: 			}
113: 
114: 			p.DefaultNavURL = dboardURL
115: 		}
116: 	}
117: }
118: 
119: // AppChildDecorateFunc is a DecorateFunc that configures child plugins of app plugins.
120: func AppChildDecorateFunc() DecorateFunc {
121: 	return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
122: 		if p.Parent != nil && p.Parent.IsApp() {
123: 			configureAppChildPlugin(p.Parent, p)
124: 		}
125: 		return p, nil
126: 	}
127: }
128: 
129: func configureAppChildPlugin(parent *plugins.Plugin, child *plugins.Plugin) {
130: 	if !parent.IsApp() {
131: 		return
132: 	}
133: 	child.IncludedInAppID = parent.ID
134: 
135: 	// If the child plugin does not have a version, it will inherit the version from the parent.
136: 	// This is to ensure that the frontend can appropriately cache the plugin assets.
137: 	if child.Info.Version == "" {
138: 		child.Info.Version = parent.Info.Version
139: 	}
140: }
141: 
142: // SkipHostEnvVarsDecorateFunc returns a DecorateFunc that configures the SkipHostEnvVars field of the plugin.
143: // It will be set to true if the plugin is not present in the ForwardHostEnvVars plugin ids list.
144: func SkipHostEnvVarsDecorateFunc(cfg *config.PluginManagementCfg) DecorateFunc {
145: 	return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
146: 		p.SkipHostEnvVars = !slices.Contains(cfg.ForwardHostEnvVars, p.ID)
147: 		return p, nil
148: 	}
149: }
150: 
151: // LoadingStrategyDecorateFunc returns a DecorateFunc that calculates and sets the loading strategy for the plugin.
152: func LoadingStrategyDecorateFunc(cfg *config.PluginManagementCfg, cdn *pluginscdn.Service) DecorateFunc {
153: 	return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
154: 		p.LoadingStrategy = pluginassets.CalculateLoadingStrategy(p, cfg, cdn)
155: 		return p, nil
156: 	}
157: }
