90: func newAngularDetector(cfg *config.PluginManagementCfg, angularInspector angularinspector.Inspector) *AngularDetector {
91: 	return &AngularDetector{
92: 		cfg:              cfg,
93: 		angularInspector: angularInspector,
94: 		log:              log.New("plugins.validator.angular"),
95: 	}
96: }
97: 
98: func (a *AngularDetector) Validate(ctx context.Context, p *plugins.Plugin) error {
99: 	// CDN plugins are ignored because they should not be using Angular
100: 	if p.FS.Type().CDN() {
101: 		return nil
102: 	}
103: 
104: 	if p.IsExternalPlugin() {
105: 		var err error
106: 
107: 		cctx, canc := context.WithTimeout(ctx, time.Second*10)
108: 		p.Angular.Detected, err = a.angularInspector.Inspect(cctx, p)
109: 		canc()
110: 
111: 		if err != nil {
112: 			a.log.Warn("Could not inspect plugin for angular", "pluginId", p.ID, "error", err)
113: 		}
114: 
115: 		// Do not initialize plugins if they're using Angular and Angular support is disabled
116: 		if p.Angular.Detected {
117: 			a.log.Error("Refusing to initialize plugin because it's using Angular, which has been disabled", "pluginId", p.ID)
118: 			return (&plugins.Error{
119: 				PluginID:  p.ID,
120: 				ErrorCode: plugins.ErrorAngular,
121: 			}).WithMessage("angular plugins are not supported")
122: 		}
123: 	}
124: 	return nil
125: }
