{"content":"1: package setting
2: 
3: import (
4: 	"os"
5: 	"regexp"
6: 	"strings"
7: 
8: 	"gopkg.in/ini.v1"
9: 
10: 	"github.com/grafana/grafana/pkg/plugins/config"
11: 	"github.com/grafana/grafana/pkg/util"
12: )
13: 
14: const (
15: 	PluginUpdateStrategyLatest = "latest"
16: 	PluginUpdateStrategyMinor  = "minor"
17: )
18: 
19: func extractPluginSettings(sections []*ini.Section) config.PluginSettings {
20: 	psMap := config.PluginSettings{}
21: 	for _, section := range sections {
22: 		sectionName := section.Name()
23: 		if !strings.HasPrefix(sectionName, "plugin.") {
24: 			continue
25: 		}
26: 
27: 		pluginID := strings.Replace(sectionName, "plugin.", "", 1)
28: 		psMap[pluginID] = section.KeysHash()
29: 	}
30: 
31: 	return psMap
32: }
33: 
34: var (
35: 	defaultPreinstallPlugins = map[string]InstallPlugin{
36: 		// Default preinstalled plugins
37: 		"grafana-lokiexplore-app":      {ID: "grafana-lokiexplore-app"},
38: 		"grafana-pyroscope-app":        {ID: "grafana-pyroscope-app"},
39: 		"grafana-exploretraces-app":    {ID: "grafana-exploretraces-app"},
40: 		"grafana-metricsdrilldown-app": {ID: "grafana-metricsdrilldown-app"},
41: 	}
42: )
43: 
44: func (cfg *Cfg) migrateInstallPluginsToPreinstallPluginsSync(rawInstallPlugins, installPluginsForce string, preinstallPluginsSync map[string]InstallPlugin) {
45: 	if strings.ToLower(installPluginsForce) == "true" || rawInstallPlugins == "" {
46: 		cfg.Logger.Debug("GF_INSTALL_PLUGINS_FORCE is set to true, skipping migration of GF_INSTALL_PLUGINS to GF_PLUGINS_PREINSTALL_SYNC")
47: 		return
48: 	}
49: 	installPluginsEntries := strings.Split(rawInstallPlugins, ",")
50: 
51: 	// Format 1: ID only (e.g., "grafana-clock-panel")
52: 	// Format 2: ID with version (e.g., "grafana-clock-panel 1.0.1")
53: 	// Format 3: URL with folder (e.g., "https://grafana.com/api/plugins/grafana-clock-panel/versions/latest/download;grafana-clock-panel")
54: 	pluginRegex := regexp.MustCompile(`(?:([^;]+);)?([^;\s]+)(?:\s+(.+))?`)
55: 	for _, entry := range installPluginsEntries {
56: 		trimmedEntry := strings.TrimSpace(entry)
57: 		if trimmedEntry == "" {
58: 			continue
59: 		}
60: 
61: 		matches := pluginRegex.FindStringSubmatch(trimmedEntry)
62: 
63: 		if matches == nil {
64: 			cfg.Logger.Debug("No match found for entry: ", trimmedEntry)
65: 			continue
66: 		}
67: 
68: 		url := ""
69: 		if len(matches) > 1 {
70: 			url = strings.TrimSpace(matches[1])
71: 		}
72: 
73: 		id := ""
74: 		if len(matches) > 2 {
75: 			id = strings.TrimSpace(matches[2])
76: 		}
77: 		if _, exists := preinstallPluginsSync[id]; exists {
78: 			continue
79: 		}
80: 
81: 		version := ""
82: 		if len(matches) > 3 {
83: 			version = strings.TrimSpace(matches[3])
84: 		}
85: 		if id != "" {
86: 			preinstallPluginsSync[id] = InstallPlugin{ID: id, Version: version, URL: url}
87: 		} else {
88: 			cfg.Logger.Debug("No ID found for entry: ", trimmedEntry, "matches: ", matches)
89: 		}
90: 	}
91: }
92: 
93: func (cfg *Cfg) processPreinstallPlugins(rawInstallPlugins []string, preinstallPlugins map[string]InstallPlugin) {
94: 	// Add the plugins defined in the configuration
95: 	for _, plugin := range rawInstallPlugins {
96: 		parts := strings.Split(plugin, "@")
97: 		id := parts[0]
98: 		version := ""
99: 		url := ""
100: 		if len(parts) > 1 {
101: 			version = parts[1]
102: 			if len(parts) > 2 {
103: 				url = strings.Join(parts[2:], "@")
104: 			}
105: 		}
106: 
107: 		preinstallPlugins[id] = InstallPlugin{id, version, url}
108: 	}
109: }
110: 
111: // readPluginAPIRestrictionsSection reads a plugin API restrictions section and returns a map of API names to plugin lists
112: func readPluginAPIRestrictionsSection(iniFile *ini.File, sectionName string) map[string][]string {
113: 	result := make(map[string][]string)
114: 
115: 	if !iniFile.HasSection(sectionName) {
116: 		return result
117: 	}
118: 
119: 	section := iniFile.Section(sectionName)
120: 	for _, key := range section.Keys() {
121: 		apiName := key.Name()
122: 		pluginList := util.SplitString(key.MustString(""))
123: 		if len(pluginList) > 0 {
124: 			result[apiName] = pluginList
125: 		}
126: 	}
127: 
128: 	return result
129: }
130: 
131: func (cfg *Cfg) readPluginSettings(iniFile *ini.File) error {
132: 	pluginsSection := iniFile.Section("plugins")
133: 
134: 	cfg.PluginsEnableAlpha = pluginsSection.Key("enable_alpha").MustBool(false)
135: 	cfg.PluginsAppsSkipVerifyTLS = pluginsSection.Key("app_tls_skip_verify_insecure").MustBool(false)
136: 	cfg.PluginSettings = extractPluginSettings(iniFile.Sections())
137: 	cfg.PluginSkipPublicKeyDownload = pluginsSection.Key("public_key_retrieval_disabled").MustBool(false)
138: 	cfg.PluginForcePublicKeyDownload = pluginsSection.Key("public_key_retrieval_on_startup").MustBool(false)
139: 
140: 	cfg.PluginsAllowUnsigned = util.SplitString(pluginsSection.Key("allow_loading_unsigned_plugins").MustString(""))
141: 	cfg.DisablePlugins = util.SplitString(pluginsSection.Key("disable_plugins").MustString(""))
142: 	cfg.ForwardHostEnvVars = util.SplitString(pluginsSection.Key("forward_host_env_vars").MustString(""))
143: 	disablePreinstall := pluginsSection.Key("preinstall_disabled").MustBool(false)
144: 	if !disablePreinstall {
145: 		rawInstallPluginsAsync := util.SplitString(pluginsSection.Key("preinstall").MustString(""))
146: 		preinstallPluginsAsync := make(map[string]InstallPlugin)
147: 		// Add the default preinstalled plugins to pre install plugins async list
148: 		for _, plugin := range defaultPreinstallPlugins {
149: 			preinstallPluginsAsync[plugin.ID] = plugin
150: 		}
151: 		if cfg.IsFeatureToggleEnabled("grafanaAdvisor") { // Use literal string to avoid circular dependency
152: 			preinstallPluginsAsync["grafana-advisor-app"] = InstallPlugin{"grafana-advisor-app", "", ""}
153: 		}
154: 		if cfg.IsFeatureToggleEnabled("interactiveLearning") { // Use literal string to avoid circular dependency
155: 			preinstallPluginsAsync["grafana-pathfinder-app"] = InstallPlugin{"grafana-pathfinder-app", "", ""}
156: 		}
157: 		cfg.processPreinstallPlugins(rawInstallPluginsAsync, preinstallPluginsAsync)
158: 
159: 		rawInstallPluginsSync := util.SplitString(pluginsSection.Key("preinstall_sync").MustString(""))
160: 		preinstallPluginsSync := make(map[string]InstallPlugin)
161: 		cfg.processPreinstallPlugins(rawInstallPluginsSync, preinstallPluginsSync)
162: 		cfg.migrateInstallPluginsToPreinstallPluginsSync(os.Getenv("GF_INSTALL_PLUGINS"), os.Getenv("GF_INSTALL_PLUGINS_FORCE"), preinstallPluginsSync)
163: 		// Remove from the list the plugins that have been disabled
164: 		for _, disabledPlugin := range cfg.DisablePlugins {
165: 			delete(preinstallPluginsAsync, disabledPlugin)
166: 			delete(preinstallPluginsSync, disabledPlugin)
167: 		}
168: 		for _, plugin := range preinstallPluginsSync {
169: 			cfg.PreinstallPluginsSync = append(cfg.PreinstallPluginsSync, plugin)
170: 			// preinstallSync plugin has priority over preinstallAsync
171: 			delete(preinstallPluginsAsync, plugin.ID)
172: 		}
173: 		for _, plugin := range preinstallPluginsAsync {
174: 			cfg.PreinstallPluginsAsync = append(cfg.PreinstallPluginsAsync, plugin)
175: 		}
176: 
177: 		installPluginsInAsync := pluginsSection.Key("preinstall_async").MustBool(true)
178: 		if !installPluginsInAsync {
179: 			for key, plugin := range preinstallPluginsAsync {
180: 				if _, exists := preinstallPluginsSync[key]; !exists {
181: 					cfg.PreinstallPluginsSync = append(cfg.PreinstallPluginsSync, plugin)
182: 				}
183: 			}
184: 			cfg.PreinstallPluginsAsync = nil
185: 		}
186: 
187: 		cfg.PreinstallAutoUpdate = pluginsSection.Key("preinstall_auto_update").MustBool(true)
188: 	}
189: 
190: 	cfg.PluginCatalogURL = pluginsSection.Key("plugin_catalog_url").MustString("https://grafana.com/grafana/plugins/")
191: 	cfg.PluginAdminEnabled = pluginsSection.Key("plugin_admin_enabled").MustBool(true)
192: 	cfg.PluginAdminExternalManageEnabled = pluginsSection.Key("plugin_admin_external_manage_enabled").MustBool(false)
193: 	cfg.PluginCatalogHiddenPlugins = util.SplitString(pluginsSection.Key("plugin_catalog_hidden_plugins").MustString(""))
194: 
195: 	// Pull disabled plugins from the catalog
196: 	cfg.PluginCatalogHiddenPlugins = append(cfg.PluginCatalogHiddenPlugins, cfg.DisablePlugins...)
197: 
198: 	// Plugins CDN settings
199: 	cfg.PluginsCDNURLTemplate = strings.TrimRight(pluginsSection.Key("cdn_base_url").MustString(""), "/")
200: 	cfg.PluginLogBackendRequests = pluginsSection.Key("log_backend_requests").MustBool(false)
201: 
202: 	cfg.PluginUpdateStrategy = pluginsSection.Key("update_strategy").In(PluginUpdateStrategyLatest, []string{PluginUpdateStrategyLatest, PluginUpdateStrategyMinor})
203: 
204: 	// Plugin API restrictions - read from sections
205: 	cfg.PluginRestrictedAPIsAllowList = readPluginAPIRestrictionsSection(iniFile, "plugins.restricted_apis_allowlist")
