250: // Filter will filter out any plugins that are marked to be disabled.
251: func (c *DisablePlugins) Filter(bundles []*plugins.FoundBundle) ([]*plugins.FoundBundle, error) {
252: 	if len(c.cfg.DisablePlugins) == 0 {
253: 		return bundles, nil
254: 	}
255: 
256: 	disablePluginsMap := make(map[string]bool)
257: 	for _, pluginID := range c.cfg.DisablePlugins {
258: 		disablePluginsMap[pluginID] = true
259: 	}
260: 
261: 	res := []*plugins.FoundBundle{}
262: 	for _, bundle := range bundles {
263: 		if disablePluginsMap[bundle.Primary.JSONData.ID] {
264: 			c.log.Debug("Disabling plugin load", "pluginID", bundle.Primary.JSONData.ID)
265: 		} else {
266: 			res = append(res, bundle)
267: 		}
268: 	}
269: 	return res, nil
270: }
271: 
272: // AsExternal is a filter step that will skip loading a core plugin to use an external one.
273: type AsExternal struct {
274: 	log log.Logger
275: 	cfg *config.PluginManagementCfg
276: }
277: 
278: // NewAsExternalStep returns a new DisablePlugins.
279: func NewAsExternalStep(cfg *config.PluginManagementCfg) *AsExternal {
280: 	return &AsExternal{
281: 		cfg: cfg,
282: 		log: log.New("plugins.asExternal"),
283: 	}
284: }
285: 
286: // Filter will filter out any plugins that are marked to be disabled.
287: func (c *AsExternal) Filter(cl plugins.Class, bundles []*plugins.FoundBundle) ([]*plugins.FoundBundle, error) {
288: 	if cl == plugins.ClassCore {
289: 		res := []*plugins.FoundBundle{}
290: 		for _, bundle := range bundles {
291: 			pluginCfg := c.cfg.PluginSettings[bundle.Primary.JSONData.ID]
292: 			// Skip core plugins if the feature flag is enabled and the plugin is in the skip list.
293: 			// It could be loaded later as an external plugin.
294: 			if pluginCfg["as_external"] == "true" {
295: 				c.log.Debug("Skipping the core plugin load", "pluginID", bundle.Primary.JSONData.ID)
296: 			} else {
297: 				res = append(res, bundle)
298: 			}
299: 		}
300: 		return res, nil
301: 	}
302: 	return bundles, nil
303: }
304: 
305: // DuplicatePluginIDValidation is a filter step that will filter out any plugins that are already registered with the same
306: // plugin ID. This includes both the primary plugin and child plugins, which are matched using the plugin.json plugin
307: // ID field.
308: type DuplicatePluginIDValidation struct {
309: 	registry registry.Service
310: 	log      log.Logger
311: }
312: 
313: // NewDuplicatePluginIDFilterStep returns a new DuplicatePluginIDValidation.
314: func NewDuplicatePluginIDFilterStep(registry registry.Service) *DuplicatePluginIDValidation {
315: 	return &DuplicatePluginIDValidation{
316: 		registry: registry,
317: 		log:      log.New("plugins.dedupe"),
318: 	}
319: }
320: 
321: // Filter will filter out any plugins that have already been registered under the same plugin ID.
322: func (d *DuplicatePluginIDValidation) Filter(ctx context.Context, bundles []*plugins.FoundBundle) ([]*plugins.FoundBundle, error) {
323: 	res := make([]*plugins.FoundBundle, 0, len(bundles))
324: 
325: 	var matchesPluginIDFunc = func(fp plugins.FoundPlugin) func(p *plugins.Plugin) bool {
326: 		return func(p *plugins.Plugin) bool {
327: 			return p.ID == fp.JSONData.ID
328: 		}
329: 	}
330: 
331: 	for _, b := range bundles {
332: 		ps := d.registry.Plugins(ctx)
333: 
334: 		if slices.ContainsFunc(ps, matchesPluginIDFunc(b.Primary)) {
335: 			d.log.Warn("Skipping loading of plugin as it's a duplicate", "pluginId", b.Primary.JSONData.ID)
336: 			continue
337: 		}
338: 
339: 		var nonDupeChildren []*plugins.FoundPlugin
340: 		for _, child := range b.Children {
341: 			if slices.ContainsFunc(ps, matchesPluginIDFunc(*child)) {
342: 				d.log.Warn("Skipping loading of child plugin as it's a duplicate", "pluginId", child.JSONData.ID)
343: 				continue
344: 			}
345: 			nonDupeChildren = append(nonDupeChildren, child)
346: 		}
347: 		res = append(res, &plugins.FoundBundle{
348: 			Primary:  b.Primary,
349: 			Children: nonDupeChildren,
350: 		})
351: 	}
352: 
353: 	return res, nil
354: }
