35: // New returns a new Validation stage.
36: func New(cfg *config.PluginManagementCfg, opts Opts) *Validate {
37: 	if opts.ValidateFuncs == nil {
38: 		opts.ValidateFuncs = DefaultValidateFuncs(cfg)
39: 	}
40: 
41: 	return &Validate{
42: 		cfg:           cfg,
43: 		validateSteps: opts.ValidateFuncs,
