49: // Validate will execute the Validate steps of the Validation stage.
50: func (v *Validate) Validate(ctx context.Context, ps *plugins.Plugin) error {
51: 	ctx, span := v.tracer.Start(ctx, "validation.Validate", trace.WithAttributes(
52: 		semconv.GrafanaPluginId(ps.ID),
53: 	))
54: 	defer span.End()
55: 
56: 	if len(v.validateSteps) == 0 {
57: 		return nil
58: 	}
